function getLiquidationProtocolFee(DataTypes.ReserveConfigurationMap memory self)
        internal
        pure
        returns (uint256)
    {
        return (self.data & LIQUIDATION_PROTOCOL_FEE_MASK)
            >> LIQUIDATION_PROTOCOL_FEE_START_BIT_POSITION;
    }

function modifyTimelockExpiration(
  bytes4 functionSelector, uint256 newTimelockExpiration
) external onlyOwner {
  // Ensure that a function selector is specified (no 0x00000000 selector).
  require(
    functionSelector != bytes4(0),
    "Function selector cannot be empty."
  );

  // Continue via logic in the inherited `_modifyTimelockExpiration` function.
  _modifyTimelockExpiration(
    functionSelector, newTimelockExpiration
  );
}

function accountRecoveryDisabled(
  address smartWallet
) external view returns (bool hasDisabledAccountRecovery) {
  // Determine if the wallet in question has opted out of account recovery.
  hasDisabledAccountRecovery = _accountRecoveryDisabled[smartWallet];
}

function getNextKeyRing(
  address userSigningKey
) external view returns (address targetKeyRing) {
  // Ensure that a user signing key has been provided.
  require(userSigningKey != address(0), "No user signing key supplied.");

  // Get initialization calldata using the initial user signing key.
  bytes memory initializationCalldata = _constructInitializationCalldata(
    userSigningKey
  );

  // Determine target key ring address based on the user signing key.
  targetKeyRing = _computeNextAddress(initializationCalldata);
}

function decreaseAllowance(address spender, uint256 subtractedValue) public virtual returns (bool) {
    address owner = msg.sender;
    uint256 currentAllowance = allowance(owner, spender);
    require(currentAllowance >= subtractedValue, "ERC20: decreased allowance below zero");
unchecked {
    _approve(owner, spender, currentAllowance - subtractedValue);
}

    return true;
}

function execute(
    address account,
    bytes32 salt,
    bytes32 mode,
    bytes calldata data
) public virtual returns (bytes[] memory returnData) {
    bytes calldata executionCalldata = _validateExecution(account, salt, mode, data);
    returnData = _execute(account, mode, salt, executionCalldata); // Prioritize errors thrown in _execute
    return returnData;
}

function _voteSucceeded(uint256 proposalId) internal view virtual override returns (bool) {
    GovernorCountingSimpleStorage storage $ = _getGovernorCountingSimpleStorage();
    ProposalVote storage proposalVote = $._proposalVotes[proposalId];

    return proposalVote.forVotes > proposalVote.againstVotes;
}

function getUpgradeInterfaceVersion(address addr) internal view returns (string memory) {
    // Use staticcall to prevent forge from broadcasting it, and to ensure no state changes
    (bool success, bytes memory returndata) = addr.staticcall(
        abi.encodeWithSignature("UPGRADE_INTERFACE_VERSION()")
    );
    if (success && returndata.length > 32) {
        return abi.decode(returndata, (string));
    } else {
        return "";
    }
}

function permitWitnessTransferFrom(
    PermitTransferFrom memory permit,
    SignatureTransferDetails calldata transferDetails,
    address owner,
    bytes32 witness,
    string calldata witnessTypeString,
    bytes calldata signature
) external {
    _permitTransferFrom(
        permit, transferDetails, owner, permit.hashWithWitness(witness, witnessTypeString), signature
    );
}

function permitTransferFrom(
    PermitBatchTransferFrom memory permit,
    SignatureTransferDetails[] calldata transferDetails,
    address owner,
    bytes calldata signature
) external {
    _permitTransferFrom(permit, transferDetails, owner, permit.hash(), signature);
}
